/* Older archive cards need a mutation that verifies the logged-in listener and never reports a silent zero-row RLS update. */ create or replace function private.touch_archived_album_review() returns trigger language plpgsql set search_path = pg_catalog as $$ begin new.updated_at := now(); return new; end; $$; revoke all on function private.touch_archived_album_review() from public, anon, authenticated; create or replace function public.save_my_archived_album_review(p_album_id text, p_review_title text, p_review text, p_rating numeric, p_best_track text, p_worst_track text, p_reset boolean default false) returns table (album_id text, review_title text, review text, rating numeric, best_track text, worst_track text, is_modified boolean) language plpgsql security definer set search_path = public, pg_temp as $$ declare current_username text; begin if (select auth.uid()) is null then raise exception 'Authentication required'; end if; select profile.username into current_username from public.member_profiles as profile where profile.id = (select auth.uid()); if current_username is null then raise exception 'Member profile not found'; end if; if p_album_id !~ '^archive-[0-9]+$' then raise exception 'Invalid archive album id'; end if; if not p_reset then if p_review is null or char_length(btrim(p_review)) = 0 then raise exception 'A review is required'; end if; if p_rating is null or p_rating < 0 or p_rating > 5 or p_rating * 2 <> trunc(p_rating * 2) then raise exception 'Rating must be between 0 and 5 in half steps'; end if; end if; return query update public.archived_album_reviews as archive_review set review_title = case when p_reset then null else coalesce(nullif(btrim(p_review_title), ''), archive_review.review_title) end, review = case when p_reset then null else btrim(p_review) end, rating = case when p_reset then null else p_rating end, best_track = case when p_reset then null else nullif(btrim(p_best_track), '') end, worst_track = case when p_reset then null else nullif(btrim(p_worst_track), '') end, is_modified = not p_reset where archive_review.album_id = p_album_id and lower(archive_review.listener_username) = lower(current_username) returning archive_review.album_id, archive_review.review_title, archive_review.review, archive_review.rating, archive_review.best_track, archive_review.worst_track, archive_review.is_modified; if not found then raise exception 'Only the assigned listener can update this archived review'; end if; end; $$; revoke all on function public.save_my_archived_album_review(text, text, text, numeric, text, text, boolean) from public, anon; grant execute on function public.save_my_archived_album_review(text, text, text, numeric, text, text, boolean) to authenticated;
